 1	import React from 'react';
 2	
 3	import NetworkInterfaceList from '@catalog/wizard/tabs/network/components/list/NetworkInterfaceList';
 4	import { V1Interface, V1Network, V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
 5	import Loading from '@kubevirt-utils/components/Loading/Loading';
 6	import SearchItem from '@kubevirt-utils/components/SearchItem/SearchItem';
 7	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 8	import { updateCustomizeInstanceType, vmSignal } from '@kubevirt-utils/store/customizeInstanceType';
 9	import { PageSection, PageSectionVariants, Title } from '@patternfly/react-core';
10	import AddNetworkInterfaceButton from '@virtualmachines/details/tabs/configuration/network/components/AddNetworkInterfaceButton';
11	
12	const CustomizeInstanceTypeNetworkTab = () => {
13	  const { t } = useKubevirtTranslation();
14	  const vm = vmSignal.value;
15	
16	  if (!vm) {
17	    return <Loading />;
18	  }
19	
20	  const onAddNetworkInterface = (updatedNetworks: V1Network[], updatedInterfaces: V1Interface[]) =>
21	    Promise.resolve(
22	      updateCustomizeInstanceType([
23	        {
24	          data: updatedNetworks,
25	          path: 'spec.template.spec.networks',
26	        },
27	        {
28	          data: updatedInterfaces,
29	          path: 'spec.template.spec.domain.devices.interfaces',
30	        },
31	      ]),
32	    );
33	
34	  const onUpdateVM = (updatedVM: V1VirtualMachine) => {
35	    updateCustomizeInstanceType([{ data: updatedVM }]);
36	    return Promise.resolve();
37	  };
38	
39	  return (
40	    <PageSection variant={PageSectionVariants.light}>
41	      <Title headingLevel="h2">
42	        <SearchItem id="network">{t('Network interfaces')}</SearchItem>
43	      </Title>
44	      <AddNetworkInterfaceButton onAddNetworkInterface={onAddNetworkInterface} vm={vm} />
45	      <NetworkInterfaceList onUpdateVM={onUpdateVM} vm={vm} />
46	    </PageSection>
47	  );
48	};
49	
50	export default CustomizeInstanceTypeNetworkTab;

